final:
module sr_latch (
    input wire S,
    input wire R,
    input wire clk,
    output reg obf_Q,
    output reg Qn
);
    always @(posedge clk) begin
        if (S && !R) begin
            obf_Q <= 1;
            Qn <= 0;
        end else if (!S && R) begin
            obf_Q <= 0;
            Qn <= 1;
        end
    end
endmodule
